package com.chaobo.scm.supplier.infrastructure.persistence.event;import com.chaobo.scm.supplier.application.outbox.*;import org.springframework.stereotype.Repository;import java.util.*;
@Repository public class MyBatisOutboxDispatchAdapter implements OutboxDispatchPort{private final EventPersistenceMapper mapper;public MyBatisOutboxDispatchAdapter(EventPersistenceMapper mapper){this.mapper=mapper;}public List<OutboxMessage> claim(int batch,int retries){var result=new ArrayList<OutboxMessage>();for(var r:mapper.findDispatchable(batch,retries)){if(mapper.markPublishing(r.eventId())==1)result.add(new OutboxMessage(r.eventId(),r.eventCode(),r.eventType(),r.aggregateType(),r.aggregateId(),r.payloadJson(),r.retryCount()));}return result;}public void markPublished(long id){mapper.markPublished(id);}public void markFailed(long id,String reason){mapper.markFailed(id,reason);}}
